('idea-generation', 'Idea Generation', 'idea-generation', 301, 'How do we generate ideas on how to answer the audience's question?', 'decks-for-decision-makers', NULL, NULL, 'How do we generate ideas on how to answer the audience's question?', 13, '2caf80c4-e364-4565-b92e-a353d4e531ff', '264486', '{"root":{"children":[{"type":"listitem","listType":"number","value":1,"children":[{"type":"text","text":"Read"},{"type":"link","url":"https://www.newyorker.com/magazine/2012/01/30/groupthink","children":[{"type":"text","text":"Group Think"}]},{"type":"text","text":"from the New Yorker, or"}]},{"type":"listitem","listType":"number","value":1,"children":[{"type":"text","text":"Watch"},{"type":"link","url":"https://www.youtube.com/watch?v=RgPIkx2JyQU","children":[{"type":"text","text":"Brainstorming: Does it work?"}]},{"type":"text","text":"from the RSA"}]},{"type":"listitem","listType":"number","value":1,"children":[{"type":"text","text":"Complete the lesson quiz"}]}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', true, '{"root":{"children":[{"type":"listitem","listType":"bullet","value":1,"children":[{"type":"text","text":"Watch"},{"type":"link","url":"https://www.youtube.com/watch?v=RgPIkx2JyQU","children":[{"type":"text","text":"Brainstorming: Does it work?"}]},{"type":"text","text":"from the RSA"}]},{"type":"listitem","listType":"bullet","value":1,"children":[{"type":"text","text":"Watch"},{"type":"link","url":"https://www.youtube.com/watch?v=M66ZU2PCIcM#aid=P-PoocZcn9w","children":[{"type":"text","text":"ABC Nightline: IDEO Shopping Cart"}]},{"type":"text","text":"for a deep dive into IDEO brainstorming techniques"}]},{"type":"listitem","listType":"bullet","value":1,"children":[{"type":"text","text":"Watch"},{"type":"link","url":"https://www.youtube.com/watch?v=4wZ5wV5dPZc","children":[{"type":"text","text":"How to Mind Map"}]},{"type":"text","text":"for an explanation of mind mapping"}]}],"direction":"ltr","format":"","indent":0,"type":"root","v